SELECT /* base.ec.pm :: PmCache :: selectList */ c.* , ste.site_nm AS site_nm , cd_ct.code_label AS cache_type_cd_nm FROM pm_cache c LEFT JOIN sy_site ste ON ste.site_id = c.site_id LEFT JOIN sy_code cd_ct ON cd_ct.code_grp = 'CACHE_TYPE' AND cd_ct.code_value = c.cache_type_cd
ORDER BY c.cache_id ASC ORDER BY c.cache_id DESC ORDER BY c.member_nm ASC ORDER BY c.member_nm DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

