site_id = #{siteId}, member_id = #{memberId}, member_nm = #{memberNm}, cache_type_cd = #{cacheTypeCd}, cache_amt = #{cacheAmt}, balance_amt = #{balanceAmt}, ref_id = #{refId}, cache_desc = #{cacheDesc}, proc_user_id = #{procUserId}, cache_date = #{cacheDate}, expire_date = #{expireDate}, upd_by = #{updBy}, upd_date = #{updDate},
